function num(n) { return n != null ? String(n) : '—'; }
function dur(n) { return n != null ? `${n} min` : '—'; }
function tok(n) { return n != null ? n.toLocaleString() : '—'; }
function score3(n) { return n != null ? n.toFixed(3) : '—'; }
function delta(a, b) {
  if (a == null || b == null) return '—';
